mapper.update:
UPDATE wf_task
SET
    status = #{toStatus},
    action = #{action},
    finish_time = NOW()
WHERE node_instance_id = #{nodeInstanceId}
  AND id != #{keepTaskId}
  AND status = #{fromStatus}

mapper.select:
select t.* from wf_task t left join wf_biz_ref wr on wr.instance_id = t.instance_id and wr.ref_type = 'PRIMARY' left join wf_instance wi on wi.id = t.instance_id where t.status = 'TODO'
AND t.assignee_id = #{userId}
order by t.create_time desc

select t.* from wf_task t left join wf_biz_ref wr on wr.instance_id = t.instance_id and wr.ref_type = 'PRIMARY' left join wf_instance wi on wi.id = t.instance_id where t.status = 'DONE'
AND t.operator_id = #{userId} or t.transfer_from = #{userId}
order by t.finish_time desc
